using System;
using System.DirectoryServices;

public class ActiveDirectoryAuthenticator
{
    public bool AuthenticateUser(string username, string password)
    {
        try
        {
            // Construct an LDAP query to find the user
            DirectoryEntry entry = new DirectoryEntry("LDAP://your-domain.com", username, password);
            DirectorySearcher searcher = new DirectorySearcher(entry);
            searcher.Filter = "(&(objectClass=user)(sAMAccountName=" + username + "))";
            SearchResult result = searcher.FindOne();

            // Check if the user was found and authenticated successfully
            if (result != null && result.Properties["userPrincipalName"][0].ToString() == username)
            {
                return true;
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine("Error: " + ex.Message);
        }

        return false;
    }
}